"""Create a self-contained interactive executive dashboard."""

from __future__ import annotations

import json
import sqlite3
from pathlib import Path


def create_report(db_path: Path, result: dict, output: Path) -> None:
    with sqlite3.connect(db_path) as conn:
        conn.row_factory = sqlite3.Row
        datasets = {
            "summary": [dict(r) for r in conn.execute("SELECT * FROM experiment_summary ORDER BY variant")],
            "funnel": [dict(r) for r in conn.execute("SELECT * FROM funnel_summary ORDER BY variant")],
            "devices": [dict(r) for r in conn.execute("SELECT * FROM segment_results")],
            "channels": [dict(r) for r in conn.execute("SELECT * FROM acquisition_results")],
            "daily": [dict(r) for r in conn.execute("SELECT * FROM daily_experiment_results")],
        }
    payload = json.dumps({"result": result, **datasets}).replace("</", "<\\/")
    document = DASHBOARD.replace("__DATA__", payload)
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_text(document, encoding="utf-8")


DASHBOARD = r'''<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="description" content="Interactive checkout A/B test product analytics dashboard">
<title>Checkout Experiment · Product Analytics</title>
<style>
:root{--ink:#102b46;--blue:#1769aa;--cyan:#2f91c8;--green:#23aa62;--orange:#f39a0b;--red:#c83a2c;--paper:#f7f9fc;--muted:#65758b;--line:#dce4ed;--navy:#0c3454}
*{box-sizing:border-box}body{margin:0;background:#eaf0f6;color:var(--ink);font:15px Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,sans-serif}.shell{max-width:1440px;margin:auto;background:white;min-height:100vh;box-shadow:0 18px 70px #102b4622}.hero{background:linear-gradient(130deg,#092e4c,#104d78);color:white;padding:35px 44px 32px;display:flex;justify-content:space-between;gap:30px;align-items:end}.eyebrow{font-size:12px;letter-spacing:2px;font-weight:800;color:#86d7ff}.hero h1{font-size:clamp(28px,4vw,52px);line-height:1;margin:8px 0 12px}.hero p{color:#bed5e5;font-size:17px;margin:0}.status{background:#ffffff14;border:1px solid #ffffff35;border-radius:14px;padding:16px 20px;min-width:210px}.status b{display:block;color:#8ef0b7;font-size:20px}.toolbar{display:flex;gap:9px;align-items:center;padding:16px 34px;border-bottom:1px solid var(--line);background:#fff;position:sticky;top:0;z-index:3;box-shadow:0 4px 16px #102b460c}.toolbar span{font-weight:750;margin-right:8px}.filter{border:1px solid #c8d4df;background:#fff;color:var(--ink);padding:8px 13px;border-radius:999px;cursor:pointer;font-weight:700}.filter.active{background:var(--blue);border-color:var(--blue);color:white}.content{padding:26px 34px 44px}.kpis{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.kpi{border:1px solid var(--line);border-top:5px solid var(--blue);padding:17px;border-radius:10px;background:#fff}.kpi:nth-child(2){border-top-color:var(--green)}.kpi:nth-child(3){border-top-color:var(--orange)}.kpi:nth-child(4){border-top-color:var(--cyan)}.kpi label{display:block;color:var(--muted);font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.6px}.kpi strong{display:block;font-size:30px;margin:5px 0 1px}.kpi small{color:var(--muted)}.grid{display:grid;grid-template-columns:1fr 1.45fr 1fr;gap:16px;margin-top:16px}.panel{border:1px solid var(--line);border-radius:10px;background:#fff;overflow:hidden}.panel h2{color:#fff;background:var(--blue);font-size:16px;margin:0;padding:12px 16px}.panel.green h2{background:var(--green)}.panel.orange h2{background:var(--orange)}.panel.red h2{background:var(--red)}.body{padding:17px}.decision{background:#e7f8ef;border-left:5px solid var(--green);padding:15px;border-radius:6px;margin-bottom:16px}.decision strong{display:block;color:#14864a;font-size:20px}.check{display:flex;justify-content:space-between;padding:10px 0;border-bottom:1px solid var(--line)}.pass{color:#14864a;font-weight:800}.chart-title{font-size:13px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);font-weight:800;margin:3px 0 12px}.legend{display:flex;gap:18px;justify-content:center;font-size:12px;margin:8px}.dot{display:inline-block;width:10px;height:10px;border-radius:50%;margin-right:5px}.bars{min-height:205px}.bar-row{display:grid;grid-template-columns:110px 1fr 58px;align-items:center;gap:9px;margin:11px 0}.track{height:13px;background:#e8edf3;border-radius:8px;overflow:hidden}.bar{height:100%;border-radius:8px;transition:width .45s}.funnel-step{display:grid;grid-template-columns:92px 1fr 1fr;gap:9px;align-items:center;margin:11px 0}.funnel-step label{font-size:12px;color:var(--muted);font-weight:700}.mini{height:23px;color:white;font-size:11px;font-weight:800;padding:4px 8px;border-radius:4px;min-width:42px;transition:width .5s}.insight{border-left:4px solid var(--orange);padding:10px 12px;background:#fff7e8;margin:12px 0}.insight b{color:#bd7000}.line-wrap{height:255px}.line-wrap svg{width:100%;height:100%;overflow:visible}.axis{stroke:#c9d4df;stroke-width:1}.gridline{stroke:#e7edf3;stroke-width:1}.line-c{fill:none;stroke:var(--blue);stroke-width:3}.line-t{fill:none;stroke:var(--green);stroke-width:3}.point{stroke:white;stroke-width:2}.tooltip{position:fixed;display:none;background:#102b46;color:white;padding:8px 10px;border-radius:6px;font-size:12px;pointer-events:none;z-index:6}.table-wrap{overflow:auto;max-height:240px}table{width:100%;border-collapse:collapse;font-size:13px}th{position:sticky;top:0;background:#eff4f8;color:var(--muted);text-transform:uppercase;font-size:11px;letter-spacing:.4px}th,td{padding:10px;text-align:right;border-bottom:1px solid var(--line)}th:first-child,td:first-child{text-align:left}.footer{display:flex;justify-content:space-between;color:var(--muted);border-top:1px solid var(--line);padding:20px 34px;font-size:12px}.span2{grid-column:span 2}@media(max-width:1000px){.grid{grid-template-columns:1fr 1fr}.span2{grid-column:span 2}.kpis{grid-template-columns:1fr 1fr}}@media(max-width:650px){.hero{display:block;padding:28px 20px}.status{margin-top:20px}.content{padding:18px}.toolbar{padding:12px 18px;overflow:auto}.grid,.kpis{grid-template-columns:1fr}.span2{grid-column:auto}.footer{display:block}.hero h1{font-size:32px}}
</style></head><body><div class="shell">
<header class="hero"><div><div class="eyebrow">PRODUCT ANALYTICS · CONTROLLED EXPERIMENT</div><h1>CHECKOUT CONVERSION<br>OPTIMIZATION</h1><p>Data-driven decisioning for a redesigned checkout progress experience</p></div><div class="status"><small>FINAL RECOMMENDATION</small><b id="heroDecision">SHIP TREATMENT</b><span id="heroConfidence">Statistically significant</span></div></header>
<nav class="toolbar"><span>Explore segments:</span><button class="filter active" data-view="device">Device</button><button class="filter" data-view="channel">Acquisition channel</button><button class="filter" data-view="overall">Overall</button></nav>
<main class="content"><section class="kpis"><div class="kpi"><label>Total users</label><strong id="totalUsers">—</strong><small>Randomized 50/50</small></div><div class="kpi"><label>Treatment conversion</label><strong id="treatRate">—</strong><small id="controlCompare">vs control</small></div><div class="kpi"><label>Relative lift</label><strong id="lift">—</strong><small>Primary metric</small></div><div class="kpi"><label>Revenue impact</label><strong id="revenueImpact">—</strong><small>Observed incremental revenue</small></div></section>
<section class="grid"><article class="panel"><h2>▣ Executive Summary</h2><div class="body"><div class="decision"><strong id="decision">Ship treatment</strong><span>The result cleared significance, allocation, and power gates.</span></div><div class="check"><span>Statistical significance</span><b class="pass" id="sigCheck">PASS</b></div><div class="check"><span>Sample-ratio mismatch</span><b class="pass" id="srmCheck">PASS</b></div><div class="check"><span>Planned power</span><b class="pass" id="powerCheck">PASS</b></div><div class="insight"><b>Why it worked</b><br>The treatment improves both cart creation and checkout completion while average order value remains stable.</div></div></article>
<article class="panel span2"><h2>▣ Daily Conversion Stability</h2><div class="body"><div class="legend"><span><i class="dot" style="background:var(--blue)"></i>Control</span><span><i class="dot" style="background:var(--green)"></i>Treatment</span></div><div class="line-wrap"><svg id="trendChart" viewBox="0 0 760 240" role="img" aria-label="Daily conversion trend"></svg></div></div></article>
<article class="panel green"><h2>▣ Segment Performance</h2><div class="body"><div class="chart-title" id="segmentTitle">Conversion by device</div><div class="legend"><span><i class="dot" style="background:var(--blue)"></i>Control</span><span><i class="dot" style="background:var(--green)"></i>Treatment</span></div><div class="bars" id="segmentBars"></div></div></article>
<article class="panel"><h2>▣ Checkout Funnel</h2><div class="body"><div class="chart-title">Users progressing through each stage</div><div id="funnel"></div><div class="insight"><b id="funnelInsight">+7.3pp</b> improvement from cart to purchase.</div></div></article>
<article class="panel orange"><h2>▣ Strategic Recommendations</h2><div class="body"><p><b>1 · Roll out progressively</b><br>Launch to 25%, monitor, then ramp to 100%.</p><p><b>2 · Prioritize mobile</b><br>Mobile shows the largest checkout friction and strongest opportunity.</p><p><b>3 · Protect guardrails</b><br>Track refunds, latency, errors, and AOV after launch.</p><p><b>4 · Run a follow-up test</b><br>Test trust messaging and payment-step simplification.</p></div></article>
<article class="panel red span2"><h2>▣ Experiment Scorecard</h2><div class="body table-wrap"><table><thead><tr><th>Variant</th><th>Users</th><th>Purchasers</th><th>Conversion</th><th>Revenue</th><th>RPU</th><th>AOV</th></tr></thead><tbody id="scoreRows"></tbody></table></div></article>
<article class="panel"><h2>▣ Statistical Evidence</h2><div class="body"><div class="check"><span>Two-sided p-value</span><b id="pvalue">—</b></div><div class="check"><span>95% lift interval</span><b id="interval">—</b></div><div class="check"><span>Required / variant</span><b id="required">—</b></div><div class="check"><span>Observed / variant</span><b id="observed">—</b></div><p style="color:var(--muted);font-size:12px">Segment cuts are diagnostic and are not treated as separately powered experiments.</p></div></article></section></main>
<footer class="footer"><span>Built by Divya Dhole · Python · SQL · SQLite · Vanilla JavaScript</span><span>Reproducible synthetic product-event data · Updated June 2026</span></footer></div><div class="tooltip" id="tooltip"></div>
<script>const D=__DATA__;
const $=s=>document.querySelector(s), fmt=n=>n.toLocaleString(), pct=n=>(n*100).toFixed(2)+'%', money=n=>'$'+Math.round(n).toLocaleString();
const c=D.summary.find(x=>x.variant==='control'),t=D.summary.find(x=>x.variant==='treatment'),r=D.result;
$('#totalUsers').textContent=fmt(c.users+t.users);$('#treatRate').textContent=pct(r.treatment_rate);$('#controlCompare').textContent='vs '+pct(r.control_rate)+' control';$('#lift').textContent=(r.relative_lift*100).toFixed(1)+'%';$('#revenueImpact').textContent=money(t.revenue-c.revenue);$('#decision').textContent=r.recommendation;$('#heroDecision').textContent=r.recommendation.toUpperCase();$('#heroConfidence').textContent='p = '+r.p_value.toExponential(2);$('#pvalue').textContent=r.p_value.toExponential(2);$('#interval').textContent=pct(r.ci_low)+' – '+pct(r.ci_high);$('#required').textContent=fmt(r.required_users_per_variant);$('#observed').textContent=fmt(Math.min(r.control_users,r.treatment_users));$('#srmCheck').textContent=r.sample_ratio_mismatch.passed?'PASS':'FAIL';$('#powerCheck').textContent=r.adequately_powered?'PASS':'FAIL';
$('#scoreRows').innerHTML=D.summary.map(x=>`<tr><td><b>${cap(x.variant)}</b></td><td>${fmt(x.users)}</td><td>${fmt(x.purchasers)}</td><td>${pct(x.conversion_rate)}</td><td>${money(x.revenue)}</td><td>$${x.revenue_per_user.toFixed(2)}</td><td>$${x.average_order_value.toFixed(2)}</td></tr>`).join('');
function cap(s){return s.charAt(0).toUpperCase()+s.slice(1)}
function renderSegments(view){let rows,title;if(view==='device'){rows=D.devices;title='Conversion by device'}else if(view==='channel'){rows=D.channels;title='Conversion by acquisition channel'}else{rows=D.summary.map(x=>({device:'All users',...x,conversion_pct:x.conversion_rate*100}));title='Overall conversion'}$('#segmentTitle').textContent=title;let key=view==='channel'?'acquisition_channel':'device';let groups=[...new Set(rows.map(x=>x[key]||'All users'))];$('#segmentBars').innerHTML=groups.map(g=>{let rr=rows.filter(x=>(x[key]||'All users')===g);return `<div style="margin-bottom:17px"><b style="font-size:12px">${cap(g.replaceAll('_',' '))}</b>${rr.map(x=>`<div class="bar-row"><span>${cap(x.variant)}</span><div class="track"><div class="bar" style="width:${Math.min(x.conversion_pct*3.2,100)}%;background:${x.variant==='treatment'?'var(--green)':'var(--blue)'}"></div></div><b>${x.conversion_pct.toFixed(2)}%</b></div>`).join('')}</div>`}).join('')}
document.querySelectorAll('.filter').forEach(b=>b.onclick=()=>{document.querySelectorAll('.filter').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderSegments(b.dataset.view)});renderSegments('device');
const fc=D.funnel.find(x=>x.variant==='control'),ft=D.funnel.find(x=>x.variant==='treatment');let stages=[['Sessions','sessions'],['Product views','product_views'],['Added to cart','carts'],['Purchases','purchases']];$('#funnel').innerHTML=stages.map(([label,key])=>`<div class="funnel-step"><label>${label}</label><div class="mini" style="width:${fc[key]/fc.sessions*100}%;background:var(--blue)">${fmt(fc[key])}</div><div class="mini" style="width:${ft[key]/ft.sessions*100}%;background:var(--green)">${fmt(ft[key])}</div></div>`).join('');$('#funnelInsight').textContent='+'+(ft.cart_to_purchase_pct-fc.cart_to_purchase_pct).toFixed(1)+'pp';
function drawTrend(){let svg=$('#trendChart'),dates=[...new Set(D.daily.map(x=>x.experiment_date))],W=760,H=240,pad=38,max=30,min=10;let xy=(v,i)=>[pad+i*(W-pad*2)/(dates.length-1),H-pad-(v-min)*(H-pad*2)/(max-min)];let out='';for(let y=10;y<=30;y+=5){let py=xy(y,0)[1];out+=`<line class="gridline" x1="${pad}" y1="${py}" x2="${W-pad}" y2="${py}"/><text x="3" y="${py+4}" fill="#65758b" font-size="11">${y}%</text>`}['control','treatment'].forEach((v,vi)=>{let rows=dates.map(d=>D.daily.find(x=>x.experiment_date===d&&x.variant===v));let pts=rows.map((x,i)=>xy(x.conversion_pct,i));out+=`<polyline class="${vi?'line-t':'line-c'}" points="${pts.map(p=>p.join(',')).join(' ')}"/>`;pts.forEach((p,i)=>out+=`<circle class="point" data-tip="${dates[i]} · ${cap(v)}: ${rows[i].conversion_pct}%" cx="${p[0]}" cy="${p[1]}" r="4" fill="${vi?'#23aa62':'#1769aa'}"/>`)});out+=`<line class="axis" x1="${pad}" y1="${H-pad}" x2="${W-pad}" y2="${H-pad}"/>`;svg.innerHTML=out;let tip=$('#tooltip');svg.querySelectorAll('[data-tip]').forEach(x=>{x.onmousemove=e=>{tip.style.display='block';tip.style.left=e.clientX+12+'px';tip.style.top=e.clientY-35+'px';tip.textContent=x.dataset.tip};x.onmouseleave=()=>tip.style.display='none'})}drawTrend();
</script></body></html>'''
